import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class CasinoJackpotUpdateParser implements IMessageParser {
private _amountRaw: string = '0';
private _amount: number = 0;

public flush(): boolean {
this._amountRaw = '0';
this._amount = 0;
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean {
if (!wrapper) return false;

// Must match CasinoJackpotUpdateComposer.java
// Server sends STRING because Arcturus 3.5.3 has no appendLong
this._amountRaw = wrapper.readString();

const parsed = Number(this._amountRaw);
this._amount = Number.isFinite(parsed) ? Math.max(0, Math.floor(parsed)) : 0;

// Optional: dispatch a global event immediately (handy for React hooks)
window.dispatchEvent(
new CustomEvent('casino_jackpot_update', {
detail: { amount: this._amount, raw: this._amountRaw }
})
);

return true;
}

/** numeric jackpot value (safe for UI) */
public get amount(): number {
return this._amount;
}

/** original string from server (safe for huge jackpots if you ever need it) */
public get amountRaw(): string {
return this._amountRaw;
}
}
